import { Component, inject, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { OrderService } from '../../core/services/order.service';
import { Order } from '../../core/models';
import { formatPrice } from '../../core/api';

@Component({
  selector: 'app-order-history',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './order-history.component.html',
  styleUrl: './order-history.component.css',
})
export class OrderHistoryComponent {
  private readonly orderService = inject(OrderService);
  readonly format = formatPrice;

  readonly orders = signal<Order[]>([
    {
      id: '1042', status: 'shipped', totalCents: 6998, shipName: 'Jane Doe',
      shipAddress: '120 Foundry Rd, Ogden, UT', createdAt: '2026-07-02T15:20:00Z',
      items: [
        { id: 'oi1', productId: '1', productName: 'CLASS-J Time-Delay Fuse 30A', quantity: 2, unitPriceCents: 1899 },
        { id: 'oi2', productId: '6', productName: 'Midget Fuse 10A 500V (Pack of 10)', quantity: 1, unitPriceCents: 3200 },
      ],
    },
    {
      id: '1039', status: 'placed', totalCents: 18900, shipName: 'Jane Doe',
      shipAddress: '120 Foundry Rd, Ogden, UT', createdAt: '2026-07-08T09:05:00Z',
      items: [
        { id: 'oi3', productId: '5', productName: 'Fused Disconnect Switch 100A', quantity: 1, unitPriceCents: 18900 },
      ],
    },
  ]);

  readonly loading = signal<boolean>(false);

  ngOnInit(): void {
    this.loading.set(true);
    this.orderService.listMine().subscribe({
      next: (list) => {
        this.orders.set(list);
        this.loading.set(false);
      },
      error: () => this.loading.set(false),
    });
  }
}
